import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{o as i,c as t,a as n,b as o,w as l,d as c,e as s,r}from"./app.e26ab0af.js";const p={},d=c(`<p>La siguiente gu\xEDa explicar\xE1 en detalle la estructura de un m\xF3dulo y c\xF3mo hacer un nuevo m\xF3dulo <strong>paso a paso</strong> dependiendo de la dificultad.</p><h2 id="estructura-de-un-modulo" tabindex="-1"><a class="header-anchor" href="#estructura-de-un-modulo" aria-hidden="true">#</a> Estructura de un m\xF3dulo</h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\u{1F4C2} Carpeta del m\xF3dulo
|\u2500\u2500 \u{1F4C2} config
|    |\u2500\u2500 \u{1F5D2}\uFE0F migration.php
|    |\u2500\u2500 \u{1F5D2}\uFE0F module.php
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F routes.php
|\u2500\u2500 \u{1F4C2} controllers
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F Module.php
|\u2500\u2500 \u{1F4C2} language
|    \u2514\u2500\u2500 \u{1F4C2} english
|        \u2514\u2500\u2500 \u{1F5D2}\uFE0F module_lang.php
|\u2500\u2500 \u{1F4C2} migrations
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F 20220511000000_create_table.php
|\u2500\u2500 \u{1F4C2} models
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F Module_model.php
\u2514\u2500\u2500 \u{1F4C2} views
     \u2514\u2500\u2500 \u{1F5D2}\uFE0F index.php
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>\u{1F4C2} <strong>config:</strong> Carpeta contenedora de configuraciones. <ul><li>\u{1F5D2}\uFE0F <strong>migration.php:</strong> Archivo de configuraci\xF3n para migraciones.</li><li>\u{1F5D2}\uFE0F <strong>module.php:</strong> Archivo de configuraci\xF3n que proporciona informaci\xF3n del m\xF3dulo.</li><li>\u{1F5D2}\uFE0F <strong>routes.php:</strong> Archivo de configuraci\xF3n para enrutamiento URI.</li></ul></li><li>\u{1F4C2} <strong>controllers:</strong> Carpeta contenedora de controladores.</li><li>\u{1F4C2} <strong>language:</strong> Carpeta contenedora de subcarpetas de idioma.</li><li>\u{1F4C2} <strong>migrations:</strong> Carpeta contenedora de archivos modificadores de base de datos.</li><li>\u{1F4C2} <strong>models:</strong> Carpeta contenedora de modelos.</li><li>\u{1F4C2} <strong>views:</strong> Carpeta contenedora de archivos de vista.</li></ul><div class="custom-container note"><p class="custom-container-title">NOTE</p><p>La estructura proporcionada aqu\xED puede variar seg\xFAn el desarrollador y la cantidad de elementos utilizados.</p></div><h2 id="como-crear-un-modulo-basico" tabindex="-1"><a class="header-anchor" href="#como-crear-un-modulo-basico" aria-hidden="true">#</a> C\xF3mo crear un m\xF3dulo b\xE1sico?</h2><p>Para comenzar esta gu\xEDa, crearemos un m\xF3dulo con el nombre <code>example</code>, el enfoque principal de este m\xF3dulo ser\xE1 mostrar un mensaje simple. Para ello crearemos la siguiente estructura:</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>\u{1F4C2} example
|\u2500\u2500 \u{1F4C2} config
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F migration.php  &lt;--- Nuevo archivo vac\xEDo
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F module.php  &lt;--- Nuevo archivo vac\xEDo
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F routes.php  &lt;--- Nuevo archivo vac\xEDo
|\u2500\u2500 \u{1F4C2} controllers
|    \u2514\u2500\u2500 \u{1F5D2}\uFE0F Example.php  &lt;--- Nuevo archivo vac\xEDo
|\u2500\u2500 \u{1F4C2} language
|\u2500\u2500 \u{1F4C2} migrations
|\u2500\u2500 \u{1F4C2} models
\u2514\u2500\u2500 \u{1F4C2} views
     \u2514\u2500\u2500 \u{1F5D2}\uFE0F index.php  &lt;--- Nuevo archivo vac\xEDo
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="custom-container info"><p class="custom-container-title">INFORMACI\xD3N</p><p>El nombre <strong>&quot;example&quot;</strong> del m\xF3dulo lo puedes cambiar por el que quieras pero ten en cuenta que tendr\xE1s que cambiar el nombre en diferentes partes del m\xF3dulo para que coincida <strong><em>(recuerda poner en may\xFAscula la primera letra en el nombre del controlador)</em></strong>.</p></div><h3 id="paso-1-archivo-de-configuracion-del-modulo" tabindex="-1"><a class="header-anchor" href="#paso-1-archivo-de-configuracion-del-modulo" aria-hidden="true">#</a> Paso 1: Archivo de configuraci\xF3n del m\xF3dulo</h3><p>Una vez que hayamos creado la estructura mencionada anteriormente, buscaremos y editaremos el archivo <code>module.php</code> en el que escribiremos lo siguiente:</p><div class="language-php ext-php line-numbers-mode"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token function">defined</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;BASEPATH&#39;</span><span class="token punctuation">)</span> <span class="token keyword">OR</span> <span class="token keyword">exit</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;No direct script access allowed&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token keyword">return</span> <span class="token punctuation">[</span>
    <span class="token string single-quoted-string">&#39;name&#39;</span>        <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;Example&#39;</span><span class="token punctuation">,</span>
    <span class="token string single-quoted-string">&#39;description&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;Un m\xF3dulo b\xE1sico simple&#39;</span><span class="token punctuation">,</span>
    <span class="token string single-quoted-string">&#39;version&#39;</span>     <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;1.0.0&#39;</span><span class="token punctuation">,</span>
    <span class="token string single-quoted-string">&#39;author&#39;</span>      <span class="token operator">=&gt;</span> <span class="token punctuation">[</span>
        <span class="token string single-quoted-string">&#39;name&#39;</span>    <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;WoW-CMS&#39;</span><span class="token punctuation">,</span>
        <span class="token string single-quoted-string">&#39;website&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;https://wow-cms.com&#39;</span>
    <span class="token punctuation">]</span><span class="token punctuation">,</span>
    <span class="token string single-quoted-string">&#39;dashboard&#39;</span>   <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;&#39;</span>
<span class="token punctuation">]</span><span class="token punctuation">;</span>
</span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Este archivo contiene informaci\xF3n importante sobre el m\xF3dulo que luego se utiliza en el CMS.</p><table><thead><tr><th>Par\xE1metro</th><th>Descripci\xF3n</th></tr></thead><tbody><tr><td><strong>name</strong></td><td>Nombre del m\xF3dulo</td></tr><tr><td><strong>description</strong></td><td>Breve descripci\xF3n del m\xF3dulo.</td></tr><tr><td><strong>version</strong></td><td>Versi\xF3n del m\xF3dulo</td></tr><tr><td><strong>author name</strong></td><td>Nombre del autor</td></tr><tr><td><strong>author website</strong></td><td>Sitio web del autor</td></tr><tr><td><strong>dashboard</strong></td><td>Ruta al panel de administraci\xF3n del m\xF3dulo</td></tr></tbody></table><div class="custom-container warning"><p class="custom-container-title">AVISO</p><p>Recuerda cambiar los datos proporcionados en el ejemplo por los tuyos.</p></div><h3 id="paso-2-archivo-de-configuracion-de-migracion" tabindex="-1"><a class="header-anchor" href="#paso-2-archivo-de-configuracion-de-migracion" aria-hidden="true">#</a> Paso 2: Archivo de configuraci\xF3n de migraci\xF3n</h3><p>Al finalizar el paso anterior, buscaremos y editaremos el archivo <code>migration.php</code> en el cual escribiremos lo siguiente:</p><div class="language-php ext-php line-numbers-mode"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token function">defined</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;BASEPATH&#39;</span><span class="token punctuation">)</span> <span class="token keyword">OR</span> <span class="token keyword">exit</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;No direct script access allowed&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">/*
|--------------------------------------------------------------------------
| Migrations Status
|--------------------------------------------------------------------------
|
| Status of the module&#39;s migration functionality. 
| Disabled by default for security reasons.
|
*/</span>
<span class="token variable">$config</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;migration_enabled&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token constant boolean">false</span><span class="token punctuation">;</span>

<span class="token comment">/*
|--------------------------------------------------------------------------
| Migrations Version
|--------------------------------------------------------------------------
|
| Parameter set as the maximum limit to proceed with the
| migration in the module.
| The version use timestamp format: YYYYMMDDHHIISS
|
*/</span>
<span class="token variable">$config</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;migration_version&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">0</span><span class="token punctuation">;</span>

<span class="token comment">/*
|--------------------------------------------------------------------------
| Migrations Path
|--------------------------------------------------------------------------
|
| Path to the module migrations folder.
|
*/</span>
<span class="token variable">$config</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;migration_path&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token string single-quoted-string">&#39;../migrations/&#39;</span><span class="token punctuation">;</span>
</span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Este archivo de configuraci\xF3n es necesario cuando el m\xF3dulo requiere entre sus funciones crear/modificar en la base de datos, pero para esta gu\xEDa no lo utilizaremos, por lo que continuaremos con los pasos.</p><h3 id="paso-3-archivo-de-configuracion-de-rutas" tabindex="-1"><a class="header-anchor" href="#paso-3-archivo-de-configuracion-de-rutas" aria-hidden="true">#</a> Paso 3: Archivo de configuraci\xF3n de rutas</h3><p>Ahora buscaremos y editaremos el \xFAltimo archivo de configuraci\xF3n <code>routes.php</code> en el que escribiremos lo siguiente:</p><div class="language-php ext-php line-numbers-mode"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token function">defined</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;BASEPATH&#39;</span><span class="token punctuation">)</span> <span class="token keyword">OR</span> <span class="token keyword">exit</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;No direct script access allowed&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token variable">$route</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;example&#39;</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token string single-quoted-string">&#39;get&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token string single-quoted-string">&#39;example/index&#39;</span><span class="token punctuation">;</span>
</span></code></pre><div class="highlight-lines"><br><br><br><div class="highlight-line">\xA0</div></div><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Este archivo de configuraci\xF3n tiene como prop\xF3sito redirigir las solicitudes a las funciones del controlador. por lo que puede limitarlos a un tipo espec\xEDfico de solicitud o cambiarles el nombre seg\xFAn lo que necesite.</p><h3 id="paso-4-archivo-de-controlador" tabindex="-1"><a class="header-anchor" href="#paso-4-archivo-de-controlador" aria-hidden="true">#</a> Paso 4: Archivo de controlador</h3><p>Habiendo terminado de preparar los archivos en la carpeta config procederemos a buscar y editar el archivo <code>Example.php</code> en la carpeta controllers en el cual escribiremos lo siguiente:</p><div class="language-php ext-php line-numbers-mode"><pre class="language-php"><code><span class="token php language-php"><span class="token delimiter important">&lt;?php</span>
<span class="token function">defined</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;BASEPATH&#39;</span><span class="token punctuation">)</span> <span class="token keyword">OR</span> <span class="token keyword">exit</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;No direct script access allowed&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token keyword">class</span> <span class="token class-name-definition class-name">Example</span> <span class="token keyword">extends</span> <span class="token class-name">MX_Controller</span>
<span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token keyword">function</span> <span class="token function-definition function">__construct</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token keyword static-context">parent</span><span class="token operator">::</span><span class="token function">__construct</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token function">mod_located</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;example&#39;</span><span class="token punctuation">,</span> <span class="token constant boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token keyword">function</span> <span class="token function-definition function">index</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    <span class="token punctuation">{</span>
        <span class="token variable">$data</span> <span class="token operator">=</span> <span class="token punctuation">[</span>
            <span class="token string single-quoted-string">&#39;message&#39;</span> <span class="token operator">=&gt;</span> <span class="token string single-quoted-string">&#39;Hello world!&#39;</span>
        <span class="token punctuation">]</span><span class="token punctuation">;</span>

        <span class="token variable">$this</span><span class="token operator">-&gt;</span><span class="token property">template</span><span class="token operator">-&gt;</span><span class="token function">build</span><span class="token punctuation">(</span><span class="token string single-quoted-string">&#39;index&#39;</span><span class="token punctuation">,</span> <span class="token variable">$data</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</span></code></pre><div class="highlight-lines"><br><br><br><br><br><br><br><br><br><div class="highlight-line">\xA0</div><br><br><div class="highlight-line">\xA0</div><br><div class="highlight-line">\xA0</div><div class="highlight-line">\xA0</div><div class="highlight-line">\xA0</div><br><div class="highlight-line">\xA0</div><br><br></div><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Este archivo se encarga de determinar c\xF3mo deben manejarse las solicitudes HTTP. En el ejemplo, puedes ver que se han marcado varias l\xEDneas para explicar su funcionalidad:</p><ul><li><strong><em>L\xEDnea 10</em>:</strong> La l\xEDnea ubicada dentro de la funci\xF3n __construct() es una funci\xF3n para verificar si el m\xF3dulo est\xE1 instalado, si no, devolver\xE1 una p\xE1gina 404.</li><li><strong><em>L\xEDnea 13</em>:</strong> La funci\xF3n principal del controlador que procesar\xE1 la solicitud.</li><li><strong><em>L\xEDneas 15 a 17</em>:</strong> Un conjunto de l\xEDneas que marcan un array asociativo de datos donde est\xE1 el mensaje que queremos mostrar.</li><li><strong><em>L\xEDnea 19</em>:</strong> Funci\xF3n de la librer\xEDa template que toma el archivo de vista <strong>(index.php)</strong> y pasa los datos con un array asociativo <strong>$data</strong>.</li></ul><h3 id="paso-5-archivo-de-vista" tabindex="-1"><a class="header-anchor" href="#paso-5-archivo-de-vista" aria-hidden="true">#</a> Paso 5: Archivo de vista</h3><p>Como paso final en esta gu\xEDa de un m\xF3dulo b\xE1sico, procederemos a buscar y editar el archivo <code>index.php</code> en la carpeta views en el que escribiremos lo siguiente:</p><div class="language-php ext-php line-numbers-mode"><pre class="language-php"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>section</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>uk-section uk-section-small primary-bg-section<span class="token punctuation">&quot;</span></span> <span class="token attr-name">uk-height-viewport</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>expand: true<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>uk-container<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h3</span><span class="token punctuation">&gt;</span></span><span class="token php language-php"><span class="token delimiter important">&lt;?=</span> <span class="token variable">$message</span> <span class="token delimiter important">?&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h3</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>section</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="highlight-lines"><br><br><div class="highlight-line">\xA0</div><br><br></div><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Este archivo mostrar\xE1 la informaci\xF3n al usuario. En el ejemplo, usamos HTML con clases de UIKit 3 y marcamos una sola l\xEDnea <strong>(L\xEDnea 3)</strong> que es donde se mostrar\xE1 nuestro <strong>&#39;Hello world!&#39;</strong>.</p><p><strong>\xA1Ya tienes tu primer m\xF3dulo b\xE1sico!</strong> Ahora primero ingresa al panel de admin, luego en la secci\xF3n de m\xF3dulos busca su nombre e inst\xE1lalo. Para proceder a verlo ve a <code>tudominio.tld/example</code> \u{1F389}</p><h2 id="como-crear-un-modulo-avanzado" tabindex="-1"><a class="header-anchor" href="#como-crear-un-modulo-avanzado" aria-hidden="true">#</a> C\xF3mo crear un m\xF3dulo avanzado?</h2>`,34),u={class:"custom-container warning"},m=n("p",{class:"custom-container-title"},"AVISO",-1),v=s("Antes de empezar, si a\xFAn no has le\xEDdo la gu\xEDa sobre "),g=s("\xBFc\xF3mo crear un m\xF3dulo b\xE1sico?"),k=s(", te recomendamos que la leas para continuar con esta gu\xEDa avanzada.");function h(b,f){const a=r("RouterLink");return i(),t("div",null,[d,n("div",u,[m,n("p",null,[v,o(a,{to:"/es/blizzcms/developer/module.html#como-crear-un-modulo-basico"},{default:l(()=>[g]),_:1}),k])])])}var _=e(p,[["render",h],["__file","module.html.vue"]]);export{_ as default};
